"""
Contains classes and functions related to the game board.
"""

class Piece:
    def __init__(self, color):
        self.color = color
        self.is_king = False

    def make_king(self):
        self.is_king = True


class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        colors = ['B', 'W']
        for row, color in enumerate(colors * 4):
            for col in range(8 if row % 2 == 0 else 7, -1, -2):
                if color == 'B':
                    self.board[row][col] = Piece('B')
                elif color == 'W':
                    self.board[row][col] = Piece('W')

    def display(self):
        for row in range(8):
            print(" ".join(f"{piece.color}{piece.is_king}".rjust(2) if piece else "--" for piece in self.board[row]))

    def get_piece(self, position):
        return self.board[position[0]][position[1]]

    def move_piece(self, start_pos, end_pos):
        piece = self.get_piece(start_pos)
        self.board[start_pos[0]][start_pos[1]] = None
        self.board[end_pos[0]][end_pos[1]] = piece

    def capture_piece(self, start_pos, end_pos, direction):
        captured_position = tuple(x + y for x, y in zip(start_pos, direction))
        if self.get_piece(captured_position):
            self.board[captured_position[0]][captured_position[1]] = None
