"""
Contains the Game class and the main function.
"""

from board import Board, Piece
from player import Player
import click

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player('B'), Player('W')]
        self.current_player_index = 0

    def start(self):
        while True:
            self.board.display()
            move = self.read_move()
            if not move:
                break
            start_pos, end_pos = move
            player = self.get_current_player()
            if not self.is_valid_move(start_pos, end_pos, player):
                click.echo("Invalid move. Please try again.")
                continue
            player.make_move(self.board, start_pos, end_pos)
            self.switch_turn()

    def read_move(self):
        prompt = f"Player {self.get_current_player().color}, enter your move (e.g., a1-b2): "
        move_input = click.prompt(prompt).lower()
        if move_input.lower() in ['q', 'quit']:
            return None
        try:
            start_pos, end_pos = move_input.split('-')
            return (ord(start_pos[0]) - ord('a'), int(start_pos[1]) - 1), (ord(end_pos[0]) - ord('a'), int(end_pos[1]) - 1)
        except Exception as e:
            click.echo(f"Invalid input: {e}")
            return None

    def is_valid_move(self, start_pos, end_pos, player):
        piece = self.board.get_piece(start_pos)
        if not piece or piece.color != player.color:
            return False
        direction = (end_pos[0] - start_pos[0], end_pos[1] - start_pos[1])
        if abs(direction[0]) != 2 or abs(direction[1]) != 2:
            return False
        return True

    def switch_turn(self):
        self.current_player_index = 1 - self.current_player_index

    def get_current_player(self):
        return self.players[self.current_player_index]


def main():
    game = Game()
    game.start()


if __name__ == "__main__":
    main()
